489	    /**
490	     * Create a new request instance from the given Laravel request.
491	     *
492	     * @param  \Illuminate\Http\Request  $from
493	     * @param  \Illuminate\Http\Request|null  $to
494	     * @return static
495	     */
496	    public static function createFrom(self $from, $to = null)
497	    {
498	        $request = $to ?: new static;
499	
500	        $files = array_filter($from->files->all());
501	
502	        $request->initialize(
503	            $from->query->all(),
504	            $from->request->all(),
505	            $from->attributes->all(),
506	            $from->cookies->all(),
507	            $files,
508	            $from->server->all(),
509	            $from->getContent()
510	        );
511	
512	        $request->headers->replace($from->headers->all());
513	
514	        $request->setRequestLocale($from->getLocale());
515	
516	        $request->setDefaultRequestLocale($from->getDefaultLocale());
517	
518	        $request->setJson($from->json());
519	
520	        if ($from->hasSession() && $session = $from->session()) {
521	            $request->setLaravelSession($session);
522	        }
523	
524	        $request->setUserResolver($from->getUserResolver());
525	
526	        $request->setRouteResolver($from->getRouteResolver());
527	
528	        return $request;
529	    }
