567	    /**
568	     * Filter the given array of files, removing any empty values.
569	     *
570	     * @param  mixed  $files
571	     * @return mixed
572	     */
573	    protected function filterFiles($files)
574	    {
575	        if (! $files) {
576	            return;
577	        }
578	
579	        foreach ($files as $key => $file) {
580	            if (is_array($file)) {
581	                $files[$key] = $this->filterFiles($files[$key]);
582	            }
583	
584	            if (empty($files[$key])) {
585	                unset($files[$key]);
586	            }
587	        }
588	
589	        return $files;
590	    }
